@dataclass(frozen=True)
class DocSpec:
    """Structured data for a generated AGENTS.md file."""

    title: str
    intro: str
    scope: tuple[str, ...]
    do: tuple[str, ...]
    avoid: tuple[str, ...]
    commands: tuple[str, ...]
    tests: tuple[str, ...]
    related_skills: tuple[str, ...]


@dataclass(frozen=True)
class BackendModuleMeta:
    """Compact metadata used to build backend service docs."""

    summary: str
    key_files: tuple[str, ...]
    invariants: tuple[str, ...]
    avoid_points: tuple[str, ...]
    tests_path: str
    tests_exist: bool
    skill_refs: tuple[str, ...] = ()
    owns_models: bool = True


@dataclass(frozen=True)
class FrontendDomainMeta:
    """Compact metadata used to build frontend subtree docs."""

    summary: str
    key_files: tuple[str, ...]
    invariants: tuple[str, ...]
    avoid_points: tuple[str, ...]
    test_focus: str
    skill_refs: tuple[str, ...] = ()


