def wrap_bullet(text: str) -> list[str]:
    """Wrap one markdown bullet item."""

    return wrap_markdown(text, initial_indent="- ", subsequent_indent="  ")


def wrap_paragraph(text: str) -> list[str]:
    """Wrap a plain paragraph."""

    return wrap_markdown(text)


def protect_inline_code(text: str) -> str:
    """Replace spaces inside inline-code spans so wrapping keeps them intact."""

    return INLINE_CODE_PATTERN.sub(
        lambda match: match.group(0).replace(" ", INLINE_CODE_SPACE),
        text,
    )


def wrap_markdown(
    text: str,
    *,
    initial_indent: str = "",
    subsequent_indent: str = "",
) -> list[str]:
    """Wrap Markdown while keeping inline-code spans on one line."""

    protected = protect_inline_code(text)
    wrapped = textwrap.fill(
        protected,
        width=WIDTH,
        initial_indent=initial_indent,
        subsequent_indent=subsequent_indent,
        break_long_words=False,
        break_on_hyphens=False,
    )
    return [line.replace(INLINE_CODE_SPACE, " ") for line in wrapped.splitlines()]


def sentence_case(text: str) -> str:
    """Normalize a metadata fragment into a sentence-like bullet."""

    normalized = text.strip()
    if not normalized:
        return normalized
    normalized = normalized[0].upper() + normalized[1:]
    if normalized[-1] not in ".!?":
        normalized += "."
    return normalized


def render_section(heading: str, items: tuple[str, ...]) -> list[str]:
    """Render a markdown section with wrapped bullets."""

    lines = [f"## {heading}", ""]
    for item in items:
        lines.extend(wrap_bullet(item))
        lines.append("")
    return lines


def render_agents(spec: DocSpec) -> str:
    """Render one AGENTS.md file."""

    lines = [DOC_COMMENT, "", f"# {spec.title}", ""]
    lines.extend(wrap_paragraph(spec.intro))
    lines.append("")
    lines.extend(render_section("Scope", spec.scope))
    lines.extend(render_section("Do", spec.do))
    lines.extend(render_section("Avoid", spec.avoid))
    lines.extend(render_section("Commands", spec.commands))
    lines.extend(render_section("Tests", spec.tests))
    lines.extend(render_section("Related Skills", spec.related_skills))
    return "\n".join(lines).rstrip() + "\n"


def render_claude(entry_name: str) -> str:
    """Render a thin CLAUDE.md wrapper."""

    lines = [
        DOC_COMMENT,
        "",
        f"# {entry_name}",
        "",
        "@AGENTS.md",
        "",
        "Use the nearest `AGENTS.md` as the shared source of truth.",
        "Keep Claude-only routing in `/.claude/rules/` or add it here only when",
        "the rule cannot live in a shared `AGENTS.md` file.",
    ]
    return "\n".join(lines).rstrip() + "\n"


def join_paths(*paths: str) -> str:
    """Format a list of relative paths for display."""

    return ", ".join(f"`{path}`" for path in paths)


def maybe_tests_note(meta: BackendModuleMeta) -> str:
    """Describe the expected pytest location."""

    if meta.tests_exist:
        return f"`{meta.tests_path}` already exists and should remain the first stop."
    return (
        f"`{meta.tests_path}` does not exist yet; create it when this service gains "
        "or changes behavior."
    )


def backend_test_command(meta: BackendModuleMeta) -> str:
    """Describe the focused backend test command for one service."""

    if meta.tests_exist:
        tests_cmd_path = meta.tests_path.removeprefix("src/api/")
        return (
            f"`cd src/api && pytest {tests_cmd_path} -q` for the narrowest focused "
            "regression pass while iterating on this module."
        )

    return (
        f"`cd src/api && pytest -q` until `{meta.tests_path}` exists; create that "
        "directory first when this service gains behavior that needs focused "
        "regression coverage."
    )


def build_backend_spec(name: str, meta: BackendModuleMeta) -> DocSpec:
    """Build one backend service AGENTS.md spec."""

    title = f"Backend Service: {name}"
    key_files = (
        join_paths(
            *(f"src/api/flaskr/service/{name}/{path}" for path in meta.key_files)
        )
        if meta.key_files
        else "No checked-in source files are present yet."
    )
    migration_command = (
        '`cd src/api && FLASK_APP=app.py flask db migrate -m "message"` and review '
        "the generated revision if schema or indexed business-key changes are made."
        if meta.owns_models
        else "`cd src/api && pytest -q` is usually enough unless work here also "
        "changes shared models in another service."
    )
    related = list(meta.skill_refs)
    related.append("`src/api/SKILL.md`")
    related.append("`SKILL.md`")
    related.append(
        "Create a new backend skill under `src/api/skills/<topic>/SKILL.md` when "
        "this module grows a repeatable multi-step debugging workflow."
    )
    return DocSpec(
        title=title,
        intro=(
            f"This file adds local guidance for `src/api/flaskr/service/{name}`. "
            "Read the repository root and `src/api/AGENTS.md` first, then use "
            "this file for module-specific ownership and risk points."
        ),
        scope=(
            f"This service owns {meta.summary}.",
            f"Primary checked-in entry files today: {key_files}",
            "Keep behavior in this module unless the concern is clearly "
            "cross-service and shared by multiple backend domains.",
            f"Preferred pytest location: {maybe_tests_note(meta)}",
        ),
        do=(
            "Start from the local entry files and preserve how this service already "
            "structures helpers, models, routes, and DTO-like helpers.",
            sentence_case(meta.invariants[0]),
            sentence_case(meta.invariants[1]),
            sentence_case(meta.invariants[2]),
        ),
        avoid=(
            sentence_case(meta.avoid_points[0]),
            sentence_case(meta.avoid_points[1]),
            sentence_case(meta.avoid_points[2]),
            "Avoid scattering service-specific rules upward into root docs when "
            "the behavior only matters inside this module.",
        ),
        commands=(
            f'`rg -n "{name}" src/api/flaskr/service src/api/tests` to locate all '
            "backend call sites and tests before editing.",
            backend_test_command(meta),
            migration_command,
            "`cd src/api && pytest -q` when a change touches shared DTOs, auth, "
            "streaming contracts, or other services in addition to this module.",
        ),
        tests=(
            f"Add or update focused tests around `{meta.tests_path}` for the happy "
            "path and the highest-risk validation, permission, or failure case.",
            "Expand coverage when payload shapes, error codes, or shared helper "
            "contracts used outside this module change.",
            "Review persistence-related changes manually for indexing, business-key "
            "semantics, and migration output whenever models move.",
            "Document any skipped provider, network, or credential-dependent checks "
            "in the final task summary.",
        ),
        related_skills=tuple(related),
    )


